import{_ as e,c as a,o as n,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Advanced: Config & Security | Antigravity-Manager","description":"Learn Antigravity Tools advanced configuration. Master security policies, scheduling, routing, monitoring, and deployment to build a stable production system.","frontmatter":{"title":"Advanced: Config & Security | Antigravity-Manager","sidebarTitle":"Advanced","subtitle":"Advanced Configuration","description":"Learn Antigravity Tools advanced configuration. Master security policies, scheduling, routing, monitoring, and deployment to build a stable production system.","order":3},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/advanced/index.md","filePath":"lbjlaq/Antigravity-Manager/advanced/index.md"}'),o={name:"lbjlaq/Antigravity-Manager/advanced/index.md"};function s(r,t,d,l,c,p){return n(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="advanced-configuration" tabindex="-1">Advanced Configuration <a class="header-anchor" href="#advanced-configuration" aria-label="Permalink to &quot;Advanced Configuration&quot;">​</a></h1><p>This chapter dives deep into Antigravity Tools&#39; advanced features: configuration management, security policies, account scheduling, model routing, quota management, monitoring and statistics, and server deployment solutions. After mastering these topics, you can upgrade Antigravity Tools from &quot;working&quot; to &quot;easy-to-use, stable, and operable.&quot;</p><h2 id="in-this-chapter" tabindex="-1">In This Chapter <a class="header-anchor" href="#in-this-chapter" aria-label="Permalink to &quot;In This Chapter&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tutorial</th><th>Description</th></tr></thead><tbody><tr><td><a href="./config/">Configuration Guide</a></td><td>Complete fields of AppConfig/ProxyConfig, disk persistence locations, and hot reload semantics</td></tr><tr><td><a href="./security/">Security &amp; Privacy</a></td><td><code>auth_mode</code>, <code>allow_lan_access</code>, and security baseline design</td></tr><tr><td><a href="./scheduling/">High-Availability Scheduling</a></td><td>Rotation, pinned accounts, sticky sessions, and failure retry mechanisms</td></tr><tr><td><a href="./model-router/">Model Routing</a></td><td>Custom mapping, wildcard priority, and preset strategies</td></tr><tr><td><a href="./quota/">Quota Management</a></td><td>Combination of Quota Protection + Smart Warmup</td></tr><tr><td><a href="./monitoring/">Proxy Monitor</a></td><td>Request logs, filtering, detail restoration, and export</td></tr><tr><td>---</td><td>---</td></tr><tr><td><a href="./context-compression/">Long Session Stability</a></td><td>Context compression, signature caching, and tool result compression</td></tr><tr><td><a href="./system/">System Features</a></td><td>Multi-language, themes, updates, startup items, and HTTP API Server</td></tr><tr><td><a href="./deployment/">Server Deployment</a></td><td>Docker noVNC vs Headless Xvfb selection and operations</td></tr></tbody></table><h2 id="recommended-learning-path" tabindex="-1">Recommended Learning Path <a class="header-anchor" href="#recommended-learning-path" aria-label="Permalink to &quot;Recommended Learning Path&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Recommended Order</p><p>This chapter covers a lot of content. It&#39;s recommended to learn in batches by module:</p></div><p><strong>Phase 1: Configuration &amp; Security (Required)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuration Guide → Security &amp; Privacy</span></span>
<span class="line"><span>config               security</span></span></code></pre></div><p>First understand the configuration system (which settings require restart, which support hot reload), then learn security settings (especially when exposing to LAN/public internet).</p><p><strong>Phase 2: Scheduling &amp; Routing (Recommended)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>High-Availability Scheduling → Model Routing</span></span>
<span class="line"><span>scheduling                   model-router</span></span></code></pre></div><p>Learn to get maximum stability with minimum accounts, then use model routing to shield from upstream changes.</p><p><strong>Phase 3: Quota &amp; Monitoring (As Needed)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quota Management → Proxy Monitor → Token Stats</span></span>
<span class="line"><span>quota               monitoring       token-stats</span></span></code></pre></div><p>Prevent silent quota exhaustion, transform call blackbox into observable system, and optimize costs quantitatively.</p><p><strong>Phase 4: Stability &amp; Deployment (Advanced)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Long Session Stability → System Features → Server Deployment</span></span>
<span class="line"><span>context-compression        system          deployment</span></span></code></pre></div><p>Solve hidden issues in long sessions, make the client more product-like, and finally learn server deployment.</p><p><strong>Quick Selection</strong>:</p><table tabindex="0"><thead><tr><th>Your Scenario</th><th>Start With</th></tr></thead><tbody><tr><td>---</td><td>---</td></tr><tr><td>Want to pin a specific model name</td><td><a href="./model-router/">Model Routing</a></td></tr><tr><td>Always running out of quota</td><td><a href="./quota/">Quota Management</a></td></tr><tr><td>Want to view request logs</td><td><a href="./monitoring/">Proxy Monitor</a></td></tr><tr><td>Want to track Token consumption</td><td><a href="./token-stats/">Token Stats</a></td></tr><tr><td>Frequent errors in long conversations</td><td><a href="./context-compression/">Long Session Stability</a></td></tr><tr><td>Need to expose to LAN</td><td><a href="./security/">Security &amp; Privacy</a></td></tr><tr><td>Need to deploy to server</td><td><a href="./deployment/">Server Deployment</a></td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Before Starting</p><ul><li>Completed <a href="./../start/">Getting Started</a> chapter (at least installation, add accounts, and start proxy)</li><li>Completed at least one protocol integration in <a href="./../platforms/">Platforms &amp; Integrations</a> (e.g., OpenAI or Anthropic)</li><li>Local reverse proxy can respond to requests normally</li></ul></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can continue learning:</p><ul><li><a href="./../faq/">FAQ</a>: Troubleshooting guide for 401/404/429/streaming interruption and other issues</li><li><a href="./../appendix/">Appendix</a>: Reference materials like endpoint quick reference, data models, z.ai capability boundaries, etc.</li></ul>`,25)])])}const g=e(o,[["render",s]]);export{h as __pageData,g as default};
